using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language arts." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their impact on civilization." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "Study of living organisms and life processes." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Email = "achen@university.edu", Bio = "Dr. Chen specializes in algorithms and machine learning. She has published over 50 papers in top-tier conferences and holds two patents in distributed computing." },
            new() { Id = 2, Name = "Dr. Robert Kim", Title = "Associate Professor", Email = "rkim@university.edu", Bio = "Dr. Kim focuses on applied mathematics and numerical analysis. He previously worked at NASA on trajectory optimization problems." },
            new() { Id = 3, Name = "Dr. Sarah Patel", Title = "Professor", Email = "spatel@university.edu", Bio = "Dr. Patel is an expert in quantum mechanics and particle physics. She has been a visiting researcher at CERN and leads the university's particle physics lab." },
            new() { Id = 4, Name = "Dr. James Wright", Title = "Associate Professor", Email = "jwright@university.edu", Bio = "Dr. Wright specializes in American literature and creative writing. He is the author of three novels and a collection of short stories." },
            new() { Id = 5, Name = "Dr. Maria Lopez", Title = "Professor", Email = "mlopez@university.edu", Bio = "Dr. Lopez is a historian focusing on Latin American history and post-colonial studies. She has received multiple grants from the National Endowment for the Humanities." },
            new() { Id = 6, Name = "Dr. David Nguyen", Title = "Assistant Professor", Email = "dnguyen@university.edu", Bio = "Dr. Nguyen researches molecular biology and genetics. His lab focuses on CRISPR gene-editing applications in agriculture." },
            new() { Id = 7, Name = "Dr. Emily Brooks", Title = "Professor", Email = "ebrooks@university.edu", Bio = "Dr. Brooks is a cybersecurity and software engineering expert with 15 years of industry experience at major tech companies before joining academia." },
            new() { Id = 8, Name = "Dr. Michael Torres", Title = "Associate Professor", Email = "mtorres@university.edu", Bio = "Dr. Torres specializes in abstract algebra and topology. He is the recipient of the university's Distinguished Teaching Award." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (lists, trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms). Prerequisite: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 305", DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, Code = "CS 310", Title = "Software Engineering", Description = "Principles of software development including requirements analysis, design patterns, testing, version control, and agile methodologies. Includes a semester-long team project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Tech Center 110", DepartmentId = 1, InstructorId = 7 },
            new() { Id = 4, Code = "CS 450", Title = "Cybersecurity Fundamentals", Description = "Overview of cybersecurity principles including cryptography, network security, access control, and ethical hacking. Hands-on lab exercises included.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Tech Center 215", DepartmentId = 1, InstructorId = 7, IsFeatured = true },

            // Mathematics
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Introduction to differential calculus: limits, continuity, derivatives, and applications. Suitable for science and engineering majors.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 102", DepartmentId = 2, InstructorId = 2 },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, matrices, linear transformations, eigenvalues, and applications to systems of equations.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Math Building 204", DepartmentId = 2, InstructorId = 8, IsFeatured = true },
            new() { Id = 7, Code = "MATH 310", Title = "Probability & Statistics", Description = "Fundamentals of probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Math Building 102", DepartmentId = 2, InstructorId = 2 },

            // Physics
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions. Calculus-based approach for science and engineering students.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", Location = "Physics Lab 101", DepartmentId = 3, InstructorId = 3 },
            new() { Id = 9, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, operators, angular momentum, and hydrogen atom. Prerequisite: PHYS 201.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Location = "Physics Lab 303", DepartmentId = 3, InstructorId = 3, IsFeatured = true },

            // English
            new() { Id = 10, Code = "ENG 101", Title = "College Writing", Description = "Development of academic writing skills including argumentation, research methods, and rhetorical analysis. Required for all first-year students.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Humanities 105", DepartmentId = 4, InstructorId = 4 },
            new() { Id = 11, Code = "ENG 250", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present. Readings include works by Hawthorne, Twain, Fitzgerald, Morrison, and others.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", Location = "Humanities 210", DepartmentId = 4, InstructorId = 4 },

            // History
            new() { Id = 12, Code = "HIST 101", Title = "World Civilizations", Description = "Survey of major world civilizations from ancient Mesopotamia to the modern era. Examines political, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Liberal Arts 301", DepartmentId = 5, InstructorId = 5, IsFeatured = true },
            new() { Id = 13, Code = "HIST 320", Title = "Modern Latin America", Description = "History of Latin America from independence movements to the present, covering revolutions, dictatorships, democratization, and globalization.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", Location = "Liberal Arts 215", DepartmentId = 5, InstructorId = 5 },

            // Biology
            new() { Id = 14, Code = "BIO 101", Title = "Introduction to Biology", Description = "Fundamental concepts of biology including cell structure, genetics, evolution, and ecology. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Tue Lab 1:00–3:50 PM", Location = "Life Sciences 101", DepartmentId = 6, InstructorId = 6 },
            new() { Id = 15, Code = "BIO 340", Title = "Molecular Biology", Description = "Study of molecular mechanisms of gene expression, DNA replication, and protein synthesis. Covers modern techniques including PCR and CRISPR.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", Location = "Life Sciences 305", DepartmentId = 6, InstructorId = 6, IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course is null ? null : GetDepartment(course.DepartmentId);
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

