{"file_text": "@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request — State University</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit a request to enroll in a course. You will receive confirmation from the registrar's office.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request for <strong>@selectedCourseName</strong> has been received. The registrar's office will process your request and contact you at your university email.</p>
        <hr />
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
        <a href="courses" class="btn btn-outline-primary ms-2">Browse Courses</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" @bind-Value="model.StudentName" class="form-control" />
                    <ValidationMessage For="() => model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" @bind-Value="model.StudentId" class="form-control" placeholder="e.g. STU-12345" />
                    <ValidationMessage For="() => model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" @bind-Value="model.CourseId" class="form-select">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Catalog.GetCourses())
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr.)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.CourseId" />
                </div>

                <div class="mb-3">
                    <label for="notes" class="form-label">Notes (optional)</label>
                    <InputTextArea id="notes" @bind-Value="model.Notes" class="form-control" rows="3" placeholder="Any additional information for the registrar…" />
                    <ValidationMessage For="() => model.Notes" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </div>
        </div>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        if (PreselectedCourseId.HasValue && model.CourseId == 0)
        {
            model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(model.CourseId);
        selectedCourseName = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        Catalog.SubmitEnrollment(model);
        submitted = true;
    }
}
", "path": "/tmp/sv-7f829ea6657449599810c6ad723c2635/UniversityCourseCatalog/Components/Pages/Enroll.razor"}

