                    <InputText id="studentId" @bind-Value="model.StudentId" class="form-control" placeholder="e.g. STU-12345" />
                    <ValidationMessage For="() => model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" @bind-Value="model.CourseId" class="form-select">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Catalog.GetCourses())
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr.)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.CourseId" />
                </div>

                <div class="mb-3">
                    <label for="notes" class="form-label">Notes (optional)</label>
                    <InputTextArea id="notes" @bind-Value="model.Notes" class="form-control" rows="3" placeholder="Any additional information for the registrar…" />
                    <ValidationMessage For="() => model.Notes" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </div>
        </div>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        if (PreselectedCourseId.HasValue && model.CourseId == 0)
        {
            model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(model.CourseId);
        selectedCourseName = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        Catalog.SubmitEnrollment(model);
        submitted = true;
    }
}

